  if (requestedMethod) {
    headers.set(
      "Access-Control-Allow-Methods",
      "GET, POST, PUT, PATCH, DELETE, OPTIONS, HEAD"
    );
  }

  return new Response(null, {
    status: 204,
    headers: headers,
  });
